import React from "react";
import CIcon from "@coreui/icons-react";
import {
  cil3d,
  cilAccountLogout,
  cilBell,
  cilBorderAll,
  cilCalculator,
  cilChartPie,
  cilChatBubble,
  cilCog,
  cilContact,
  cilCursor,
  cilDescription,
  cilDrop,
  cilNotes,
  cilPencil,
  cilPeople,
  cilPuzzle,
  cilSpeedometer,
  cilStar,
  cilUser,
  cilHandshake
} from "@coreui/icons";
import { CNavGroup, CNavItem, CNavTitle } from "@coreui/react";
import authService from "./auth/auth.service";

let _nav = [];

const getVisibleNavItems = (navItems) => {
  const visibleNavItems = navItems && navItems.filter(item => item.visible);
  return visibleNavItems
};

if (authService.getPermission("DASHBOARD_TAB")) {
  _nav.push({
    component: CNavItem,
    name: "Dashboard",
    to: "/dashboard",
    icon: <CIcon icon={cilBorderAll} customClassName="nav-icon fa" />,
  });
}

// Add navigation item for 'Business Queries' for BUSINESS permission
if (authService.getPermission("BUSINESS_REQUEST_TAB") || authService.getPermission("BUSINESS_PAGE_QUERY_TAB")) {
  _nav.push({
    component: CNavGroup,
    name: "Business Queries",
    to: "/base",
    icon: <CIcon icon={cilContact} customClassName="nav-icon" />,
    items: getVisibleNavItems(
      [
        {
          component: CNavItem,
          name: "Contact Us",
          to: "/business",
          visible: authService.getPermission("BUSINESS_REQUEST_TAB"),
        },
        {
          component: CNavItem,
          name: "Page Query",
          to: "/user-view-query",
          visible: authService.getPermission("BUSINESS_PAGE_QUERY_TAB"),
        },
      ],
    ),
  });
}

// Add navigation item for 'Contact' for CONTACT permission
if (authService.getPermission("CONTACT_TAB")) {

  _nav.push({
    component: CNavGroup,
    name: "Contact",
    to: "/base",
    icon: <CIcon icon={cilContact} customClassName="nav-icon" />,
    items: getVisibleNavItems(
      [
        {
          component: CNavItem,
          name: "Interest",
          to: "/interest",
          visible: authService.getPermission("INTEREST_TAB"),
        },
        {
          component: CNavItem,
          name: "Persona",
          to: "/persona",
          visible: authService.getPermission("PERSONA_TAB"),
        },
      ],
    ),
  });

}

// Add navigation item for 'Testimonial' for TESTIMONIAL permission
if (authService.getPermission("TESTIMONIAL_TAB")) {
  _nav.push({
    component: CNavItem,
    name: "Testimonial",
    to: "/testimonial",
    icon: <CIcon icon={cilChatBubble} customClassName="nav-icon" />,
  });
}

// Add navigation item for 'Resource' for RESOURCE permission
if (authService.getPermission("CATEGORY_TAB") || authService.getPermission("BLOG_TAB") || authService.getPermission("TRIVIA_TAB") || authService.getPermission("INFOGRAPHIC_TAB")) {
  _nav.push({
    component: CNavGroup,
    name: "Resource",
    to: "/base",
    icon: <CIcon icon={cilCog} customClassName="nav-icon" />,
    items: getVisibleNavItems(
      [
        {
          component: CNavItem,
          name: "Category",
          to: "/category",
          visible: authService.getPermission("CATEGORY_TAB"),
        },
        {
          component: CNavItem,
          name: "Blog",
          to: "/blog",
          visible: authService.getPermission("BLOG_TAB"),
        },
        {
          component: CNavItem,
          name: "Trivia",
          to: "/trivia",
          visible: authService.getPermission("TRIVIA_TAB"),
        },
        {
          component: CNavItem,
          name: "Infographic",
          to: "/infrograpic",
          visible: authService.getPermission("INFOGRAPHIC_TAB"),
        },
      ],
    )

  });
}

// Add navigation item for 'Team' for TEAM permission
if (authService.getPermission("TEAM_TAB") || authService.getPermission("POSITION_TAB")) {
  _nav.push({
    component: CNavGroup,
    name: "Team",
    to: "/base",
    icon: <CIcon icon={cilPeople} customClassName="nav-icon" />,
    items: getVisibleNavItems(
      [
        {
          component: CNavItem,
          name: "Position",
          to: "/position",
          visible: authService.getPermission("POSITION_TAB"),

        },
        {
          component: CNavItem,
          name: "Team",
          to: "/team",
          visible: authService.getPermission("TEAM_TAB"),
        },
      ],
    )
  });
}

// Add navigation item for 'Career' for CAREER permission
if (authService.getPermission("DEPARTMENT_TAB") || authService.getPermission("CAREER_POSITION_TAB") || authService.getPermission("APPLICANTS_TAB") || authService.getPermission("JOB_DESCRIPTION_TAB")) {
  _nav.push({
    component: CNavGroup,
    name: "Career",
    to: "/base",
    icon: <CIcon icon={cil3d} customClassName="nav-icon" />,

    items: getVisibleNavItems(
      [
        {
          component: CNavItem,
          name: "Departments",
          to: "/career/department",
          visible: authService.getPermission("DEPARTMENT_TAB"),
        },
        {
          component: CNavItem,
          name: "Positions",
          to: "/career/position",
          visible: authService.getPermission("CAREER_POSITION_TAB"),
        },
        {
          component: CNavItem,
          name: "JD",
          to: "/career/job-description",
          visible: authService.getPermission("JOB_DESCRIPTION_TAB"),
        },
        {
          component: CNavItem,
          name: "Applicants",
          to: "/career/applicant",
          visible: authService.getPermission("APPLICANTS_TAB"),
        },
      ]
    )
  });
}

if (authService.getPermission("SIGN_UP_CODE_TAB")) {

  _nav.push({
    component: CNavItem,
    name: "Signup code",
    to: "/code",
    icon: <CIcon icon={cilHandshake} customClassName="nav-icon" />,
  });
}

if (authService.getPermission("SUBSCRPTION_TAB")) {
  _nav.push({
    component: CNavGroup,
    name: "Members",
    to: "/base",
    icon: <CIcon icon={cilUser} customClassName="nav-icon" />,
    items: getVisibleNavItems(
      [
        {
          component: CNavItem,
          name: "Product",
          to: "/product",
          visible: authService.getPermission("PRODUCT_TAB"),
        },
        {
          component: CNavItem,
          name: "Subscription Plan",
          to: "/subcription-plan",
          visible: authService.getPermission("SUBSCRIPTION_PLAN_TAB"),
        },
        {
          component: CNavItem,
          name: "Members summary",
          to: "/members-summary",
          visible: authService.getPermission("SUBSCRPTION_SUMMARY_TAB"),
        },
        {
          component: CNavItem,
          name: "Payment Received",
          to: "/payment-received",
          visible: authService.getPermission("PAYMENT_RECEIVED_TAB"),
        },
        {
          component: CNavItem,
          name: "Payment Refunded",
          to: "/payment-refunded",
          visible: authService.getPermission("PAYMENT_REFUNDED_TAB"),
        },
        // {
        //   component: CNavItem,
        //   name: "Transactions",
        //   to: "/transaction",
        //   visible: authService.getPermission("TRANSACTION_TAB"),
        // },
      ]
    )
  });
}

// Add navigation item for 'User' for USER permission
if (authService.getPermission("ROLE_TAB") || authService.getPermission("USER_TAB")) {
  _nav.push({
    component: CNavGroup,
    name: "User",
    to: "/base",
    icon: <CIcon icon={cilUser} customClassName="nav-icon" />,
    items: getVisibleNavItems(
      [
        {
          component: CNavItem,
          name: "Role",
          to: "/role",
          visible: authService.getPermission("ROLE_TAB"),
        },
        {
          component: CNavItem,
          name: "User",
          to: "/user",
          visible: authService.getPermission("USER_TAB"),
        },
      ]
    )
  });
}

_nav.push({
  component: CNavItem,
  name: "Logout",
  to: "/logout",
  icon: <CIcon icon={cilAccountLogout} customClassName="nav-icon" />,
});

export default _nav;
